import items from './data.json';

const styles = `
  .table-wrapper {
    width: 100%;
    overflow-x: auto;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  }

  .simple-table {
    width: 100%;
    border-collapse: collapse;
    border: 1px solid #e0e0e0;
    font-size: 14px;
  }

  .simple-table thead {
    background-color: #f5f5f5;
  }

  .simple-table th {
    padding: 12px 16px;
    text-align: left;
    font-weight: 600;
    color: #333;
    border-bottom: 2px solid #ccc;
    white-space: nowrap;
  }

  .simple-table td {
    padding: 10px 16px;
    border-bottom: 1px solid #e0e0e0;
    color: #555;
    max-width: 300px;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  .simple-table tbody tr:hover {
    background-color: #f9f9f9;
  }

  .simple-table .cell-stringified {
    color: #666;
    font-style: italic;
  }

  .simple-table .cell-high-price {
    color: #d32f2f;
    font-weight: 600;
  }

  .table-empty {
    padding: 40px;
    text-align: center;
    color: #999;
    font-size: 15px;
  }
`;

function formatCellValue(value, key) {
  if (key && key.toLowerCase() === 'price') {
    const num = Number(value);
    if (!isNaN(num) && num > 6) {
      return <span className="cell-high-price">{String(value)}</span>;
    }
  }
  if (value === null || value === undefined) {
    return <span style={{ color: '#bbb' }}>-</span>;
  }
  if (Array.isArray(value) || typeof value === 'object') {
    const str = JSON.stringify(value);
    return <span className="cell-stringified" title={str}>{str}</span>;
  }
  return String(value);
}

function normalizeRows(data) {
  if (!Array.isArray(data)) {
    return [data];
  }
  return data;
}

function collectKeys(rows) {
  const keySet = new Set();
  for (const row of rows) {
    if (row && typeof row === 'object') {
      for (const key of Object.keys(row)) {
        keySet.add(key);
      }
    }
  }
  return Array.from(keySet);
}

export default function App() {
  const rows = normalizeRows(items);
  const keys = collectKeys(rows);

  return (
    <>
      <style>{styles}</style>
      <div className="table-wrapper">
        {rows.length === 0 ? (
          <div className="table-empty">No data to display</div>
        ) : (
          <table className="simple-table">
            <thead>
              <tr>
                {keys.map(key => (
                  <th key={key}>{key}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {rows.map((row, i) => (
                <tr key={i}>
                  {keys.map(key => (
                    <td key={key} title={formatCellValue(row?.[key], key)}>
                      {formatCellValue(row?.[key], key)}
                    </td>
                  ))}
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </>
  );
}

