import items from './data.json';

const onSalesItems = Array.isArray(items) ? items.filter(item => Number(item.price) > 6) : [];
const currentPriceItems = Array.isArray(items) ? items.filter(item => Number(item.price) <= 6) : [];

export default function App() {
  return (
    <div style={styles.container}>
      <h1 style={styles.heading}>Product Inventory</h1>

      <div style={styles.tableWrapper}>
        <h2 style={styles.subHeading}>
          <span style={styles.badge}>On Sale</span>
          {onSalesItems.length} items
        </h2>
        <table style={styles.table}>
          <thead>
            <tr style={styles.headerRow}>
              <th style={styles.th}>Item</th>
              <th style={styles.th}>Price</th>
            </tr>
          </thead>
          <tbody>
            {onSalesItems.map((item, index) => (
              <tr
                key={index}
                style={{
                  ...styles.row,
                  background: index % 2 === 0 ? '#fff7ed' : '#fff',
                }}
              >
                <td style={styles.td}>{item.name || item.title || String(item)}</td>
                <td style={styles.td}>${Number(item.price).toFixed(2)}</td>
              </tr>
            ))}
          </tbody>
        </table>
        {onSalesItems.length === 0 && (
          <p style={styles.empty}>No items on sale.</p>
        )}
      </div>

      <div style={styles.tableWrapper}>
        <h2 style={styles.subHeading}>
          <span style={{ ...styles.badge, background: '#e0f2fe', color: '#0369a1' }}>Current Price</span>
          {currentPriceItems.length} items
        </h2>
        <table style={styles.table}>
          <thead>
            <tr style={styles.headerRow}>
              <th style={styles.th}>Item</th>
              <th style={styles.th}>Price</th>
            </tr>
          </thead>
          <tbody>
            {currentPriceItems.map((item, index) => (
              <tr
                key={index}
                style={{
                  ...styles.row,
                  background: index % 2 === 0 ? '#f0fdf4' : '#fff',
